'use client';

import { useEffect, useRef, useState, useCallback } from 'react';
import { useSearchParams } from 'next/navigation';
import { XIcon } from 'lucide-react';
import { NavHeader } from '@/components/ui/nav-header';
import { BuildingCanvas } from './viewport/building-canvas';
import { BuildingToolbar } from './toolbar/building-toolbar';
import { LayerPanel } from './panels/layer-panel';
import { PalettePanel } from './panels/palette-panel';
import { BomPanel } from './panels/bom-panel';
import { HazardPanel } from './panels/hazard-panel';
import { SkillsPanel } from './panels/skills-panel';
import { useBuildingState } from '@/hooks/use-building-state';
import { decodeBuildingState, generateBuildingShareUrl } from '@/lib/building/building-encoder';
import { ALL_TILES } from '@/data/building';
import { DEMO_STATE } from '@/data/building/demo';
import { BuildingOnboarding } from './onboarding/building-onboarding';

const STRIP_KEY = 'kdx_building_strip_v1';

export function BuildingShell() {
  const searchParams = useSearchParams();
  const hook = useBuildingState();
  const isLoadedRef = useRef(false);
  const [showStrip, setShowStrip] = useState(false);

  useEffect(() => {
    try {
      if (!localStorage.getItem(STRIP_KEY)) setShowStrip(true);
    } catch {}
  }, []);

  const dismissStrip = useCallback(() => {
    try { localStorage.setItem(STRIP_KEY, '1'); } catch {}
    setShowStrip(false);
  }, []);

  const loadDemo = useCallback(() => {
    hook.loadState(DEMO_STATE);
    dismissStrip();
  }, [hook, dismissStrip]);

  // On mount, load state from URL if present
  useEffect(() => {
    if (!isLoadedRef.current && searchParams && searchParams.size > 0) {
      const decoded = decodeBuildingState(searchParams);
      hook.loadState(decoded);
      isLoadedRef.current = true;
    }
  }, [searchParams]);

  // Sync state back to URL when layout changes
  useEffect(() => {
    if (!isLoadedRef.current && searchParams.size > 0) return;
    const newUrl = generateBuildingShareUrl(hook.state, window.location.origin);
    if (window.location.href !== newUrl) {
      window.history.replaceState(null, '', newUrl);
    }
  }, [hook.state.cells, hook.state.name, hook.state.activeLayer, hook.state.claimX, hook.state.claimZ]);

  // Global hotkeys
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (
        document.activeElement instanceof HTMLInputElement ||
        document.activeElement instanceof HTMLTextAreaElement
      ) return;

      const k = e.key.toLowerCase();
      if (k === 'r')                    hook.rotateTile();
      else if (k === 'q')               hook.setMode('place');
      else if (k === 'e')               hook.setMode('erase');
      else if (k === 'f')               hook.setMode('fill');
      else if (k === 's')               hook.setMode('select');
      else if (k === 'i')               hook.setMode('eyedropper');
      else if (k === 'v')               hook.setMode('pan');
      else if (k === 'm')               hook.setMode('measure');
      else if (k === 'z' && (e.ctrlKey || e.metaKey)) { e.preventDefault(); hook.undo(); }
      else if (k === 'y' && (e.ctrlKey || e.metaKey)) { e.preventDefault(); hook.redo(); }
      else if (k === 'z' && (e.ctrlKey || e.metaKey) && e.shiftKey) { e.preventDefault(); hook.redo(); }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [hook]);

  // Compute tile cap count (only tiles where countedInCap = true)
  const tileMap = ALL_TILES.reduce((m, t) => { m.set(t.id, t); return m; }, new Map<string, typeof ALL_TILES[0]>());
  const tileCount = hook.state.cells.filter((c) => tileMap.get(c.tileId)?.countedInCap !== false).length;

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-sr-bg text-slate-200">
      <NavHeader />

      {/* ── Value strip — first-visit only, dismissible ─────────────── */}
      {showStrip && (
        <div className="shrink-0 border-b border-sr-border bg-sr-surface/60 px-4 py-2.5 flex items-center gap-4 flex-wrap">
          <div className="flex flex-col min-w-0">
            <p className="text-[9px] font-mono uppercase tracking-[0.25em] text-sr-muted">
              Architectural Design Interface
            </p>
            <p className="text-xs font-mono text-slate-300 leading-snug">
              Plan Stars Reach builds in 3D before you place a single block
            </p>
          </div>
          <div className="flex items-center gap-2 flex-wrap">
            {[
              'Design inside claim limits',
              'Auto-generates materials list',
              'Shows required skills',
            ].map((chip) => (
              <span key={chip} className="text-[9px] font-mono text-teal-400 border border-teal-800/60 bg-teal-950/30 px-2 py-0.5 uppercase tracking-wide shrink-0">
                {chip}
              </span>
            ))}
          </div>
          <div className="flex items-center gap-2 ml-auto shrink-0">
            <button
              onClick={loadDemo}
              className="text-[9px] font-mono uppercase tracking-widest px-3 py-1.5 border border-cyan-700/60 text-cyan-300 bg-cyan-600/10 hover:bg-cyan-600/20 transition-colors"
            >
              Load Demo →
            </button>
            <button
              onClick={dismissStrip}
              className="text-slate-600 hover:text-slate-400 transition-colors"
              title="Dismiss"
            >
              <XIcon className="w-3.5 h-3.5" />
            </button>
          </div>
        </div>
      )}

      <div className="flex-1 flex overflow-hidden relative">

        {/* First-visit orientation tour + persistent ? button */}
        <BuildingOnboarding />

        {/* Left Panel: Layers + Claim Config */}
        <div className="w-60 border-r border-sr-border bg-sr-surface flex flex-col z-10">
          {/* Claim size configurator */}
          <div className="px-3 py-2 border-b border-sr-border">
            <p className="text-[8px] font-mono uppercase tracking-[0.3em] text-slate-600">
              Claim Size
            </p>
            <p className="text-[7px] font-mono text-slate-700 mb-2">Stay inside your planned footprint</p>
            <div className="flex items-center gap-2">
              <div className="flex-1">
                <label className="text-[7px] font-mono text-slate-600 uppercase tracking-widest block mb-0.5">W</label>
                <input
                  type="number"
                  min={4}
                  max={32}
                  value={hook.state.claimX}
                  onChange={(e) => hook.setClaimSize(parseInt(e.target.value, 10) || 10, hook.state.claimZ)}
                  className="w-full bg-sr-bg border border-sr-border px-2 py-1 text-xs font-mono text-slate-300 focus:border-cyan-700 focus:outline-none"
                />
              </div>
              <span className="text-slate-600 font-mono text-xs mt-4">×</span>
              <div className="flex-1">
                <label className="text-[7px] font-mono text-slate-600 uppercase tracking-widest block mb-0.5">D</label>
                <input
                  type="number"
                  min={4}
                  max={32}
                  value={hook.state.claimZ}
                  onChange={(e) => hook.setClaimSize(hook.state.claimX, parseInt(e.target.value, 10) || 10)}
                  className="w-full bg-sr-bg border border-sr-border px-2 py-1 text-xs font-mono text-slate-300 focus:border-cyan-700 focus:outline-none"
                />
              </div>
              <span className="text-[8px] font-mono text-slate-700 mt-4">units</span>
            </div>
          </div>

          <LayerPanel
            layers={hook.state.layers}
            activeLayer={hook.state.activeLayer}
            hiddenLayers={hook.state.hiddenLayers ?? []}
            cells={hook.state.cells}
            onSetActiveLayer={hook.setActiveLayer}
            onRenameLayer={hook.renameLayer}
            onToggleLayerVisibility={hook.toggleLayerVisibility}
          />
        </div>

        {/* Center: 3D Viewport */}
        <div className="flex-1 relative bg-sr-bg">
          <BuildingCanvas
            state={hook.state}
            onPlaceCell={hook.placeCell}
            onPlaceCellBatch={hook.placeCellBatch}
            onEraseCell={hook.eraseCell}
            onEraseCellBatch={hook.eraseCellBatch}
            onEyedropCell={hook.eyedropCell}
            onPickUpCell={hook.pickUpCell}
          />

          <BuildingToolbar
            mode={hook.state.mode}
            onSetMode={hook.setMode}
            canUndo={hook.canUndo}
            canRedo={hook.canRedo}
            onUndo={hook.undo}
            onRedo={hook.redo}
            onRotate={hook.rotateTile}
            tileCount={tileCount}
          />
        </div>

        {/* Right Panel: Palette + Analysis */}
        <div className="w-80 border-l border-sr-border bg-sr-bg flex flex-col z-10 overflow-y-auto">
          <PalettePanel
            selectedTileId={hook.state.selectedTileId}
            onSelectTile={hook.selectTile}
          />
          <HazardPanel
            cells={hook.state.cells}
            claimX={hook.state.claimX}
            claimZ={hook.state.claimZ}
          />
          <BomPanel
            cells={hook.state.cells}
          />
          <SkillsPanel
            cells={hook.state.cells}
          />
        </div>

      </div>
    </div>
  );
}

/**
 * chain-view.tsx
 * Crafting dependency chain visualizer and shopping list.
 * One concern: rendering the production tree and raw material totals.
 *
 * Shows:
 *   - Tree of crafting steps (recursive sub-components)
 *   - Ordered crafting steps (bottom-up)
 *   - Total raw materials shopping list
 */

'use client';

import { useMemo } from 'react';
import type { Recipe, Resource } from '@/types/crafting';
import { resolveChain } from '@/lib/crafting/chain-resolver';
import type { ChainNode, ResolvedChain } from '@/lib/crafting/chain-resolver';

export interface ChainViewProps {
  recipe: Recipe;
  quantity: number;
  recipeMap: Map<string, Recipe>;
  recipeByOutput: Map<string, Recipe>;
  resourceMap: Map<string, Resource>;
}

export function ChainView({
  recipe,
  quantity,
  recipeMap,
  recipeByOutput,
  resourceMap,
}: ChainViewProps) {
  const chain = useMemo(
    () => resolveChain(recipe.id, quantity, recipeMap, recipeByOutput),
    [recipe.id, quantity, recipeMap, recipeByOutput],
  );

  const hasChain = chain.steps.length > 1 || chain.shoppingList.length > 0;

  if (!hasChain) {
    return (
      <div className="text-xs text-slate-500 py-4 text-center">
        No sub-components — this recipe uses only raw materials.
      </div>
    );
  }

  return (
    <div className="flex flex-col gap-4">
      {/* Shopping list */}
      <ShoppingList chain={chain} resourceMap={resourceMap} />

      {/* Ordered crafting steps */}
      <CraftingSteps chain={chain} resourceMap={resourceMap} />

      {/* Tree view */}
      <div>
        <h4 className="text-xs font-semibold text-slate-300 uppercase tracking-wider mb-2">
          Dependency Tree
        </h4>
        <div className="pl-2 border-l border-slate-700">
          <TreeNode node={chain.tree} resourceMap={resourceMap} />
        </div>
      </div>
    </div>
  );
}

/** Raw materials shopping list */
function ShoppingList({
  chain,
  resourceMap,
}: {
  chain: ResolvedChain;
  resourceMap: Map<string, Resource>;
}) {
  if (chain.shoppingList.length === 0) return null;

  return (
    <div className="rounded-md border border-amber-800/30 bg-amber-950/15 p-3">
      <h4 className="text-xs font-semibold text-amber-300 uppercase tracking-wider mb-2">
        Raw Materials Needed
      </h4>
      <div className="space-y-1">
        {chain.shoppingList
          .sort((a, b) => b.totalQuantity - a.totalQuantity)
          .map((entry) => {
            const resource = resourceMap.get(entry.resourceId);
            return (
              <div key={entry.resourceId} className="flex justify-between text-xs">
                <span className="text-slate-300">
                  {resource?.name ?? entry.resourceId}
                </span>
                <span className="text-amber-400 tabular-nums font-mono">
                  &times;{entry.totalQuantity}
                </span>
              </div>
            );
          })}
      </div>
    </div>
  );
}

/** Ordered crafting steps */
function CraftingSteps({
  chain,
  resourceMap,
}: {
  chain: ResolvedChain;
  resourceMap: Map<string, Resource>;
}) {
  return (
    <div>
      <h4 className="text-xs font-semibold text-slate-300 uppercase tracking-wider mb-2">
        Crafting Order
      </h4>
      <ol className="space-y-1.5">
        {chain.steps.map((step) => (
          <li
            key={step.recipeId}
            className="flex items-start gap-2 text-xs rounded-md bg-slate-800/40 px-2 py-1.5"
          >
            <span className="shrink-0 w-5 h-5 flex items-center justify-center bg-slate-700 text-[10px] font-mono text-slate-300">
              {step.order + 1}
            </span>
            <div className="flex-1 min-w-0">
              <span className="text-slate-200 font-medium">{step.recipeName}</span>
              <span className="text-slate-500 ml-1">
                &times;{step.craftCount} at {step.stationId}
              </span>
            </div>
          </li>
        ))}
      </ol>
    </div>
  );
}

/** Recursive tree node renderer */
function TreeNode({
  node,
  resourceMap,
}: {
  node: ChainNode;
  resourceMap: Map<string, Resource>;
}) {
  return (
    <div className="py-1">
      <div className="flex items-center gap-1.5 text-xs">
        <span className="text-slate-300 font-medium">{node.recipeName}</span>
        <span className="text-slate-600">&times;{node.craftCount}</span>
        <span className="text-slate-600 text-[9px] capitalize">({node.stationId})</span>
      </div>
      {node.children.length > 0 && (
        <div className="ml-3 pl-2 border-l border-slate-700/50 mt-0.5">
          {node.children.map((child) => (
            <TreeNode key={child.recipeId} node={child} resourceMap={resourceMap} />
          ))}
        </div>
      )}
    </div>
  );
}

/**
 * stat-optimizer-panel.tsx
 * UI for the resource stat optimizer — the crafting calculator's killer feature.
 * One concern: letting players input P/Q/R/V values and see predicted output stats.
 *
 * Mechanic (CraftingScreenModel.cs CalculateStatValue):
 *   Per stat: collect 1 value per slot → sort desc → drop 1 (2-4 slots) or 2 (5 slots) → round(avg)
 *   All 4 stats appear in output; effectiveQuality = avg of all 4.
 */

'use client';

import { useState, useMemo, useCallback } from 'react';
import type { Recipe, Resource, ResourceStats, StatKey, ResourceInput } from '@/types/crafting';
import { STAT_KEYS, STAT_LABELS, STAT_NAMES } from '@/types/crafting';
import { calculateOutputStats, suggestOptimalStat } from '@/lib/crafting/stat-optimizer';

export interface StatOptimizerPanelProps {
  recipe: Recipe;
  resourceMap: Map<string, Resource>;
}

/** Color for each stat */
const STAT_COLORS: Record<StatKey, string> = {
  potential: 'text-amber-400',
  quality: 'text-emerald-400',
  resilience: 'text-blue-400',
  versatility: 'text-violet-400',
};

const STAT_BAR_COLORS: Record<StatKey, string> = {
  potential: 'bg-amber-500',
  quality: 'bg-emerald-500',
  resilience: 'bg-blue-500',
  versatility: 'bg-violet-500',
};

export function StatOptimizerPanel({ recipe, resourceMap }: StatOptimizerPanelProps) {
  // Initialize input stats from base stats for each ingredient
  const [inputStats, setInputStats] = useState<Map<string, ResourceStats>>(() => {
    const map = new Map<string, ResourceStats>();
    for (const ing of recipe.ingredients) {
      const resource = resourceMap.get(ing.resourceId);
      map.set(ing.resourceId, resource?.baseStats ?? defaultStats());
    }
    return map;
  });

  const [planetNames, setPlanetNames] = useState<Map<string, string>>(new Map());

  // Build ResourceInput array for the optimizer
  const inputs: ResourceInput[] = useMemo(
    () =>
      recipe.ingredients.map((ing) => ({
        resourceId: ing.resourceId,
        stats: inputStats.get(ing.resourceId) ?? defaultStats(),
        planetName: planetNames.get(ing.resourceId),
      })),
    [recipe.ingredients, inputStats, planetNames],
  );

  // Run optimization
  const result = useMemo(
    () => calculateOutputStats(inputs, recipe.ingredients),
    [inputs, recipe.ingredients],
  );

  // Stat suggestion for this recipe's output type
  const suggestion = useMemo(
    () => suggestOptimalStat(recipe.output.category),
    [recipe.output.category],
  );

  const updateStat = useCallback(
    (resourceId: string, stat: StatKey, value: number) => {
      setInputStats((prev) => {
        const next = new Map(prev);
        const current = next.get(resourceId) ?? defaultStats();
        next.set(resourceId, { ...current, [stat]: value });
        return next;
      });
    },
    [],
  );

  return (
    <div className="flex flex-col gap-4">
      {/* Suggestion banner */}
      <div className="p-2 rounded-md bg-cyan-950/30 border border-cyan-800/30">
        <p className="text-xs text-cyan-300">
          <span className="font-semibold">Tip:</span> {suggestion.reason}{' '}
          Prioritize{' '}
          <span className={STAT_COLORS[suggestion.primary]}>
            {STAT_NAMES[suggestion.primary]}
          </span>{' '}
          and{' '}
          <span className={STAT_COLORS[suggestion.secondary]}>
            {STAT_NAMES[suggestion.secondary]}
          </span>.
        </p>
      </div>

      {/* Per-ingredient stat inputs */}
      {recipe.ingredients.map((ing) => {
        const resource = resourceMap.get(ing.resourceId);
        const stats = inputStats.get(ing.resourceId) ?? defaultStats();

        return (
          <IngredientStatInput
            key={ing.resourceId}
            resourceId={ing.resourceId}
            resourceName={resource?.name ?? ing.resourceId}
            quantity={ing.quantity}
            stats={stats}
            onStatChange={updateStat}
          />
        );
      })}

      {/* Results section */}
      <ResultDisplay result={result} />
    </div>
  );
}

// ── Sub-components ────────────────────────────────────────────────

function IngredientStatInput({
  resourceId,
  resourceName,
  quantity,
  stats,
  onStatChange,
}: {
  resourceId: string;
  resourceName: string;
  quantity: number;
  stats: ResourceStats;
  onStatChange: (id: string, stat: StatKey, value: number) => void;
}) {
  return (
    <div className="rounded-md border border-slate-700 p-2.5 bg-slate-800/30">
      <div className="flex justify-between items-center mb-2">
        <span className="text-xs font-medium text-slate-200">{resourceName}</span>
        <span className="text-xs text-slate-500">&times;{quantity}</span>
      </div>
      <div className="grid grid-cols-4 gap-2">
        {STAT_KEYS.map((key) => (
          <div key={key} className="flex flex-col items-center gap-1">
            <label className={`text-xs font-mono font-bold ${STAT_COLORS[key]}`}>
              {STAT_LABELS[key]}
            </label>
            <input
              type="number"
              min={0}
              max={100}
              value={stats[key]}
              onChange={(e) => onStatChange(resourceId, key, Number(e.target.value) || 0)}
              className="w-full bg-slate-900 border border-slate-600 rounded px-1.5 py-1 text-xs text-center text-slate-200 focus:border-cyan-400 focus:outline-none tabular-nums"
            />
          </div>
        ))}
      </div>
    </div>
  );
}

function ResultDisplay({
  result,
}: {
  result: ReturnType<typeof calculateOutputStats>;
}) {
  return (
    <div className="border border-teal-800/40 bg-teal-950/20 p-3">
      <h4 className="text-xs font-semibold text-teal-300 uppercase tracking-wider mb-2">
        Predicted Output
      </h4>

      {/* Effective quality score */}
      <div className="flex items-baseline justify-between mb-3">
        <span className="text-sm text-slate-300">Effective Quality</span>
        <span className="text-xl font-bold font-mono text-teal-400">
          {result.effectiveQuality.toFixed(1)}
        </span>
      </div>

      {/* Stat bars */}
      <div className="space-y-1.5">
        {STAT_KEYS.map((key) => {
          const value = result.finalStats[key];
          return (
            <div key={key} className="flex items-center gap-2">
              <span className={`w-4 text-xs font-mono font-bold ${STAT_COLORS[key]}`}>
                {STAT_LABELS[key]}
              </span>
              <div className="flex-1 h-2 rounded-full bg-slate-700 overflow-hidden">
                <div
                  className={`h-full rounded-full transition-all duration-300 ${STAT_BAR_COLORS[key]}`}
                  style={{ width: `${Math.min(value, 100)}%` }}
                />
              </div>
              <span className="w-8 text-right text-xs font-mono tabular-nums text-slate-300">
                {value}
              </span>
            </div>
          );
        })}
      </div>

      {/* Drop mechanic note */}
      <p className="mt-2 text-xs text-slate-500">
        {result.droppedCount === 2
          ? '2 lowest values per stat dropped (5-slot recipe).'
          : '1 lowest value per stat dropped.'}{' '}
        Values rounded to nearest integer per game formula.
      </p>
    </div>
  );
}

function defaultStats(): ResourceStats {
  return { potential: 50, quality: 50, resilience: 50, versatility: 50 };
}

/**
 * planner-shell.tsx
 * Client-side planner shell — owns useSearchParams and build state.
 * One concern: composing sidebar + canvas with URL param decoding.
 *
 * Extracted from page.tsx so the page can wrap this in <Suspense>,
 * which Next.js 16 requires for useSearchParams().
 * Source: https://nextjs.org/docs/messages/missing-suspense-with-csr-bailout
 */

'use client';

import { useMemo, useCallback, useState } from 'react';
import { useSearchParams } from 'next/navigation';
import { ReactFlowProvider } from '@xyflow/react';

import { NavHeader } from '@/components/ui/nav-header';
import { TreeCanvas } from '@/components/tree/tree-canvas';
import { ProfessionList } from '@/components/sidebar/profession-list';
import { SkillCounter } from '@/components/sidebar/skill-counter';
import { ToolTracker } from '@/components/sidebar/tool-tracker';
import { BuildValidationPanel } from '@/components/sidebar/build-validation';
import { StatAllocator } from '@/components/sidebar/stat-allocator';
import { SkillDetailPanel } from '@/components/planner/skill-detail-panel';
import { ToolSelectModal } from '@/components/planner/tool-select-modal';
import { SavedBuildsPanel } from '@/components/planner/saved-builds-panel';
import { OnboardingHints } from '@/components/planner/onboarding-hints';
// Tooltip available if needed; currently unused
import { useBuildState } from '@/hooks/use-build-state';
import { useSavedBuilds } from '@/hooks/use-saved-builds';
import { encodeBuild, decodeBuild } from '@/lib/build-encoder';
import {
  getAllProfessions,
  getProfessionMap,
  getNodeMap,
  getProfessionSummaries,
} from '@/data/professions/index';
import type { SkillNodeState } from '@/types/skill-tree';

/** Static data — computed once at module load, not per render */
const ALL_PROFESSIONS = getAllProfessions();
const PROFESSION_MAP = getProfessionMap();
const NODE_MAP = getNodeMap();
const SUMMARIES = getProfessionSummaries();

/** Derive node visual state from build — mirrors flow-converter.ts resolveNodeState */
function resolveNodeState(
  nodeId: string,
  activeSkills: string[],
  atrophiedSkills: string[],
): SkillNodeState {
  const node = NODE_MAP.get(nodeId);
  if (!node) return 'locked';
  if (!node.implemented) return 'wip';
  if (activeSkills.includes(nodeId)) return 'in_practice';
  if (atrophiedSkills.includes(nodeId)) return 'out_of_practice';
  if (node.prerequisites.length === 0) return 'available';
  const prereqsMet = node.prerequisites.every(
    (pid) => activeSkills.includes(pid) || atrophiedSkills.includes(pid),
  );
  return prereqsMet ? 'available' : 'locked';
}

export function PlannerShell() {
  const searchParams = useSearchParams();

  // Decode shared build from URL params if present
  const initialBuild = useMemo(() => {
    if (searchParams.has('s') || searchParams.has('n')) {
      const decoded = decodeBuild(searchParams);
      // Encoder only stores professionId — resolve actual tool names from profession map
      decoded.toolSlots = decoded.toolSlots.map((slot) => {
        if (!slot.professionId) return slot;
        const prof = PROFESSION_MAP.get(slot.professionId);
        return prof ? { ...slot, toolName: prof.tool.name } : slot;
      });
      return decoded;
    }
    return undefined;
  }, []); // Only decode once on mount — intentional empty deps

  const state = useBuildState({
    professions: ALL_PROFESSIONS,
    professionMap: PROFESSION_MAP,
    nodeMap: NODE_MAP,
    summaries: SUMMARIES,
    initialBuild,
  });

  const saves = useSavedBuilds();

  // Tool select modal state
  const [toolModalSlot, setToolModalSlot] = useState<number | null>(null);

  // Share button feedback
  const [shareCopied, setShareCopied] = useState(false);

  const handleShare = useCallback(() => {
    const encoded = encodeBuild(state.build);
    const url = `${window.location.origin}/planner?${encoded}`;
    navigator.clipboard.writeText(url).then(() => {
      setShareCopied(true);
      setTimeout(() => setShareCopied(false), 2000);
    });
  }, [state.build]);

  const handleLoadSave = useCallback(
    (id: string) => {
      const build = saves.loadBuild(id);
      if (build) state.loadBuild(build);
    },
    [saves, state],
  );

  // Compute detail panel data from selectedNodeId
  const detailNode = state.selectedNodeId ? NODE_MAP.get(state.selectedNodeId) ?? null : null;
  const detailState = state.selectedNodeId
    ? resolveNodeState(
        state.selectedNodeId,
        state.build.activeSkills,
        state.build.atrophiedSkills,
      )
    : null;
  const detailProfName = detailNode
    ? (PROFESSION_MAP.get(detailNode.professionId)?.name ?? detailNode.professionId)
    : '';

  return (
    <div className="flex flex-col h-dvh overflow-hidden">
      <NavHeader />
      <div className="flex flex-1 overflow-hidden">

        {/* ── Left sidebar ─────────────────────────────────── */}
        <aside className="w-72 shrink-0 flex flex-col gap-3 p-3 bg-sr-surface border-r border-sr-border overflow-y-auto">

          {/* First-use guidance */}
          <OnboardingHints />

          {/* Build name + share */}
          <div className="flex items-center gap-2">
            <input
              type="text"
              value={state.build.name}
              onChange={(e) => state.setBuildName(e.target.value)}
              className="flex-1 bg-transparent border-b border-sr-border text-sm text-sr-text px-1 py-0.5 focus:border-cyan-400 focus:outline-none transition-colors"
              placeholder="Build name..."
            />
            <button
              onClick={handleShare}
              className={`shrink-0 text-xs px-2 py-1 rounded transition-colors ${
                shareCopied
                  ? 'bg-teal-700/50 text-teal-300'
                  : 'bg-cyan-800/40 text-cyan-300 hover:bg-cyan-800/60'
              }`}
              title="Copy share URL to clipboard"
            >
              {shareCopied ? '✓ Copied' : 'Share'}
            </button>
          </div>

          {/* Skill budget */}
          <SkillCounter build={state.build} allNodes={state.nodeMap} />

          {/* Tool loadout */}
          <ToolTracker
            build={state.build}
            onSlotClick={(idx) => setToolModalSlot(idx)}
          />

          {/* Stat pools */}
          <StatAllocator
            stats={state.build.stats}
            onStatsChange={state.updateStats}
          />

          {/* Validation feedback */}
          <BuildValidationPanel validation={state.validation} />

          {/* Saved builds */}
          <SavedBuildsPanel
            currentBuild={state.build}
            savedBuilds={saves.savedBuilds}
            onSave={saves.saveBuild}
            onLoad={handleLoadSave}
            onDelete={saves.deleteBuild}
          />

          {/* Profession browser */}
          <ProfessionList
            professions={state.summaries}
            selectedIds={state.selectedProfessionIds}
            onToggle={state.toggleProfession}
          />

          {/* Reset button */}
          <button
            onClick={state.resetBuild}
            className="mt-auto text-xs px-3 py-1.5 rounded bg-red-900/30 text-red-400 border border-red-800/40 hover:bg-red-900/50 transition-colors"
          >
            Reset Build
          </button>
        </aside>

        {/* ── Main canvas area ─────────────────────────────── */}
        <main className="flex-1 relative overflow-hidden">
          <ReactFlowProvider>
            <TreeCanvas
              initialNodes={state.flowNodes}
              initialEdges={state.flowEdges}
              onSkillClick={state.toggleSkill}
              onSkillSelect={state.selectNode}
            />
          </ReactFlowProvider>

          {/* Skill detail panel — floats over bottom-right of canvas */}
          <SkillDetailPanel
            node={detailNode}
            nodeState={detailState}
            build={state.build}
            professionName={detailProfName}
            onClose={() => state.selectNode(null)}
          />
        </main>
      </div>

      {/* Tool selection modal */}
      {toolModalSlot !== null && (
        <ToolSelectModal
          slotIndex={toolModalSlot}
          toolSlots={state.build.toolSlots}
          professions={ALL_PROFESSIONS}
          onEquip={(idx, prof) => {
            state.equipTool(idx, prof);
            // Auto-show this profession's tree on the canvas
            if (!state.selectedProfessionIds.includes(prof.id)) {
              state.toggleProfession(prof.id);
            }
            setToolModalSlot(null);
          }}
          onClear={(idx) => {
            state.clearTool(idx);
            setToolModalSlot(null);
          }}
          onClose={() => setToolModalSlot(null)}
        />
      )}
    </div>
  );
}

/**
 * stat-allocator.tsx
 * Sidebar widget for allocating the 3 stat pools: Health, Stamina, Focus.
 * One concern: distributing 100 points across 3 pools with validation.
 *
 * Stars Reach gives players a fixed pool of stat points to distribute.
 * Adjusting one slider shifts available points for the others.
 * Total must always equal 100.
 */

'use client';

import { useCallback } from 'react';
import { Tooltip } from '@/components/ui/tooltip';
import type { StatAllocation } from '@/types/build';

const TOTAL = 100;
const MIN_STAT = 10;

const STAT_CONFIG = [
  {
    key: 'health' as const,
    label: 'Health',
    color: 'text-red-400',
    trackColor: 'accent-red-500',
    bgColor: 'bg-red-500',
    barBg: 'bg-red-900/30',
    description: 'Max HP and recovery rate',
  },
  {
    key: 'stamina' as const,
    label: 'Stamina',
    color: 'text-amber-400',
    trackColor: 'accent-amber-500',
    bgColor: 'bg-amber-500',
    barBg: 'bg-amber-900/30',
    description: 'Sprint, jump, tool use costs',
  },
  {
    key: 'focus' as const,
    label: 'Focus',
    color: 'text-sky-400',
    trackColor: 'accent-sky-500',
    bgColor: 'bg-sky-500',
    barBg: 'bg-sky-900/30',
    description: 'Skill cooldowns and XP gain rate',
  },
] as const;

export interface StatAllocatorProps {
  stats: StatAllocation;
  onStatsChange: (stats: StatAllocation) => void;
}

export function StatAllocator({ stats, onStatsChange }: StatAllocatorProps) {
  const total = stats.health + stats.stamina + stats.focus;
  const remaining = TOTAL - total;

  const handleChange = useCallback(
    (key: keyof StatAllocation, rawValue: number) => {
      // Clamp value between MIN and what's available
      const maxForOthers = (Object.keys(stats) as (keyof StatAllocation)[])
        .filter((k) => k !== key)
        .reduce((sum, k) => sum + MIN_STAT, 0);
      const maxValue = TOTAL - maxForOthers;
      const value = Math.max(MIN_STAT, Math.min(maxValue, rawValue));

      // Distribute the difference across the other two stats proportionally
      const diff = stats[key] - value;
      const otherKeys = (Object.keys(stats) as (keyof StatAllocation)[]).filter((k) => k !== key);
      const otherTotal = otherKeys.reduce((sum, k) => sum + stats[k], 0);

      const newStats = { ...stats, [key]: value };

      if (otherTotal > 0) {
        let leftover = diff;
        otherKeys.forEach((k, i) => {
          if (i === otherKeys.length - 1) {
            // Last key gets remaining to avoid rounding errors
            newStats[k] = Math.max(MIN_STAT, stats[k] + leftover);
          } else {
            const share = Math.round((stats[k] / otherTotal) * diff);
            newStats[k] = Math.max(MIN_STAT, stats[k] + share);
            leftover -= share;
          }
        });
      }

      // Ensure total is exactly 100
      const newTotal = newStats.health + newStats.stamina + newStats.focus;
      if (newTotal !== TOTAL) {
        const adj = TOTAL - newTotal;
        const lastKey = otherKeys[otherKeys.length - 1];
        newStats[lastKey] = Math.max(MIN_STAT, newStats[lastKey] + adj);
      }

      onStatsChange(newStats);
    },
    [stats, onStatsChange],
  );

  return (
    <div className="flex flex-col gap-2 p-3 rounded-lg bg-slate-800/50 border border-slate-700">
      <div className="flex items-baseline justify-between">
        <h3 className="text-xs font-semibold text-slate-300 uppercase tracking-wider flex items-center gap-1">
          Stat Pools
          <Tooltip content="Distribute 100 points across Health, Stamina, and Focus. Each stat has a minimum of 10. Adjusting one slider redistributes the remainder proportionally.">
            <span className="text-slate-500 hover:text-slate-300 cursor-help text-[10px]">?</span>
          </Tooltip>
        </h3>
        <span
          className={`text-xs font-mono ${Math.abs(remaining) > 0 ? 'text-red-400' : 'text-slate-500'}`}
          title="Should always be 100"
        >
          {total}/{TOTAL}
        </span>
      </div>

      <div className="space-y-2.5">
        {STAT_CONFIG.map(({ key, label, color, trackColor, bgColor, barBg, description }) => {
          const value = stats[key];
          const pct = (value / TOTAL) * 100;
          return (
            <div key={key}>
              <div className="flex items-baseline justify-between mb-1">
                <span className={`text-[11px] font-medium ${color}`}>{label}</span>
                <span className="text-xs font-mono text-slate-300 tabular-nums">{value}</span>
              </div>

              {/* Visual bar */}
              <div className={`relative h-1.5 rounded-full ${barBg} mb-1.5`}>
                <div
                  className={`absolute left-0 top-0 h-full rounded-full ${bgColor} transition-all duration-150`}
                  style={{ width: `${pct}%` }}
                />
              </div>

              {/* Slider input */}
              <input
                type="range"
                min={MIN_STAT}
                max={TOTAL - MIN_STAT * 2}
                value={value}
                onChange={(e) => handleChange(key, Number(e.target.value))}
                className={`w-full h-1 rounded-full appearance-none cursor-pointer ${trackColor}`}
                title={description}
              />
            </div>
          );
        })}
      </div>

      <p className="text-[9px] text-slate-600 leading-tight mt-0.5">
        Adjust to match your preferred playstyle. Total must equal 100.
      </p>
    </div>
  );
}

/**
 * skill-node.tsx
 * Custom React Flow node for displaying a single skill in the tree.
 * One concern: rendering a skill node with its visual state, badges, and handles.
 *
 * Visual states (mapped from SkillNodeState):
 *   locked          → dimmed, grey border, no interaction
 *   available       → bright border, pulsing glow, clickable
 *   in_practice     → solid fill (teal), active indicator
 *   out_of_practice → faded fill, dashed border
 *   wip             → striped/hatched, "WIP" badge
 *
 * Source: @xyflow/react v12 custom nodes
 *   https://reactflow.dev/learn/customization/custom-nodes
 */

'use client';

import { memo, useCallback } from 'react';
import { Handle, Position } from '@xyflow/react';
import type { NodeProps } from '@xyflow/react';
import type { SkillFlowNode } from '@/types/flow-nodes';
import type { SkillNodeState } from '@/types/skill-tree';

/** CSS class map for each visual state */
const STATE_STYLES: Record<SkillNodeState, string> = {
  locked:
    'border-slate-600 bg-slate-800/60 text-slate-500 cursor-not-allowed opacity-50',
  available:
    'border-cyan-400 bg-slate-900 text-cyan-100 cursor-pointer hover:shadow-cyan-500/30 hover:shadow-lg ring-1 ring-cyan-400/20',
  in_practice:
    'border-teal-400 bg-teal-900/80 text-teal-50 cursor-pointer shadow-teal-500/25 shadow-md',
  out_of_practice:
    'border-amber-500/60 bg-amber-950/40 text-amber-200/80 cursor-pointer border-dashed',
  wip:
    'border-purple-500/50 bg-purple-950/30 text-purple-300/70 cursor-help',
};

/** Small colored dot indicating state at a glance */
const STATE_INDICATOR: Record<SkillNodeState, string> = {
  locked: 'bg-slate-600',
  available: 'bg-cyan-400 animate-pulse',
  in_practice: 'bg-teal-400',
  out_of_practice: 'bg-amber-500',
  wip: 'bg-purple-500',
};

/** Tier label colors */
const TIER_COLORS: Record<number, string> = {
  0: 'text-slate-400',
  1: 'text-blue-400',
  2: 'text-indigo-400',
  3: 'text-violet-400',
};

function SkillNodeComponent({ data, id }: NodeProps<SkillFlowNode>) {
  const {
    label,
    description,
    state,
    tier,
    special,
    unlocksTree,
    implemented,
    costs,
  } = data;

  const stateClass = STATE_STYLES[state];
  const indicatorClass = STATE_INDICATOR[state];
  const tierColor = TIER_COLORS[tier] ?? 'text-fuchsia-400';

  const handleClick = useCallback(() => {
    if (state === 'locked' || state === 'wip') return;
    // Dispatch is handled by the parent via onNodeClick — this is just for
    // stopping propagation on non-interactive states
  }, [state]);

  return (
    <div
      className={`
        relative rounded-lg border-2 px-3 py-2
        min-w-[140px] max-w-[180px]
        transition-all duration-200 ease-out
        ${stateClass}
      `}
      onClick={handleClick}
      title={description}
    >
      {/* Target handle (incoming edges from prerequisites) */}
      <Handle
        type="target"
        position={Position.Top}
        className="!w-2 !h-2 !bg-slate-500 !border-slate-400"
      />

      {/* State indicator dot */}
      <div className="flex items-center gap-1.5 mb-1">
        <span className={`inline-block w-2 h-2 rounded-full ${indicatorClass}`} />
        <span className={`text-xs font-mono uppercase ${tierColor}`}>
          T{tier}
        </span>
      </div>

      {/* Node name */}
      <p className="text-xs font-semibold leading-tight truncate">{label}</p>

      {/* Cost row */}
      {costs && (
        <p className="text-xs font-mono text-slate-500 mt-0.5 tabular-nums">
          {costs.exp.toLocaleString()} EXP · {costs.klaatu.toLocaleString()} KL
        </p>
      )}

      {/* Badges row */}
      <div className="flex gap-1 mt-1.5 flex-wrap">
        {/* Special badge */}
        {special && (
          <span
            className="inline-flex items-center gap-0.5 rounded-full bg-amber-800/60 px-1.5 py-0.5 text-xs font-medium text-amber-200"
            title={`Special: ${special.name} — ${special.description}`}
          >
            S
          </span>
        )}

        {/* Tree unlock badge */}
        {unlocksTree && (
          <span
            className="inline-flex items-center gap-0.5 rounded-full bg-cyan-800/60 px-1.5 py-0.5 text-xs font-medium text-cyan-200"
            title={`Unlocks: ${unlocksTree}`}
          >
            &rarr;
          </span>
        )}

        {/* WIP badge */}
        {!implemented && (
          <span className="inline-flex items-center rounded-full bg-purple-800/60 px-1.5 py-0.5 text-xs font-medium text-purple-200">
            WIP
          </span>
        )}
      </div>

      {/* Source handle (outgoing edges to dependents) */}
      <Handle
        type="source"
        position={Position.Bottom}
        className="!w-2 !h-2 !bg-slate-500 !border-slate-400"
      />
    </div>
  );
}

/**
 * Memoized export — React Flow re-renders nodes on every pan/zoom,
