/**
 * command-console.tsx
 * Kodaxa relay console — press ~ anywhere to open.
 * One concern: diegetic command interface with in-world responses.
 *
 * Supported commands:
 *   help          — list available commands
 *   status        — system health readout
 *   ping <sector> — mock latency to a named sector
 *   whoami        — operative identity check
 *   clear         — clear output
 *   uplink        — navigate to auth
 *   ops           — navigate to /planner
 *   intel         — navigate to /items
 *   commerce      — navigate to /directory
 *   dispatch      — navigate to /patch-notes
 *   corp          — navigate to /corporation
 *   exit / close  — dismiss console
 */

'use client';

import { useEffect, useRef, useState, useCallback } from 'react';
import { useRouter } from 'next/navigation';

// ── Types ──────────────────────────────────────────────────────────────

interface ConsoleLine {
  type: 'input' | 'output' | 'error' | 'system';
  text: string;
}

// ── Command definitions ────────────────────────────────────────────────

const HELP_OUTPUT = [
  '  help              — list available commands',
  '  status            — system health readout',
  '  ping <sector>     — relay ping to a named sector',
  '  whoami            — operative identity check',
  '  uplink            — navigate to authentication',
  '  ops               — open Operations division',
  '  intel             — open Intelligence division',
  '  commerce          — open Commerce division',
  '  dispatch          — open Dispatch newsroom',
  '  corp              — open Corporation Registry',
  '  clear             — clear console output',
  '  exit              — close relay console',
].join('\n');

const STATUS_OUTPUT = [
  '  Satellite uplink       ● NOMINAL',
  '  Relay network          ● NOMINAL',
  '  Schematics Archive     ● ONLINE',
  '  Material Registry      ● ONLINE',
  '  Commerce Registry      ● ONLINE',
  '  Workforce Intelligence ● ONLINE',
  '  Data pipeline          ● SYNCING',
  '  Server locality        FRONTIER-WEST-3',
].join('\n');

function pingOutput(sector: string): string {
  const ms = Math.floor(Math.random() * 120) + 20;
  const name = sector || 'UNKNOWN';
  return `  RELAY_PING ${name.toUpperCase()} — ${ms}ms — uplink stable`;
}

// ── Component ──────────────────────────────────────────────────────────

export function CommandConsole() {
  const [open, setOpen]       = useState(false);
  const [input, setInput]     = useState('');
  const [history, setHistory] = useState<ConsoleLine[]>([
    { type: 'system', text: 'KODAXA RELAY CONSOLE · Type `help` for commands · Press ~ or Esc to close' },
  ]);
  const [cmdHistory, setCmdHistory]   = useState<string[]>([]);
  const [historyIdx, setHistoryIdx]   = useState(-1);
  const inputRef  = useRef<HTMLInputElement>(null);
  const outputRef = useRef<HTMLDivElement>(null);
  const router    = useRouter();

  // Open/close on ~ key
  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if (e.key === '`' || e.key === '~') {
        e.preventDefault();
        setOpen((v) => !v);
      }
      if (e.key === 'Escape') setOpen(false);
    };
    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, []);

  // Focus input when opened
  useEffect(() => {
    if (open) setTimeout(() => inputRef.current?.focus(), 50);
  }, [open]);

  // Scroll to bottom on new output
  useEffect(() => {
    if (outputRef.current) {
      outputRef.current.scrollTop = outputRef.current.scrollHeight;
    }
  }, [history]);

  const addLine = useCallback((lines: ConsoleLine[]) => {
    setHistory((h) => [...h, ...lines]);
  }, []);

  const runCommand = useCallback((raw: string) => {
    const trimmed = raw.trim();
    if (!trimmed) return;

    const [cmd, ...args] = trimmed.toLowerCase().split(/\s+/);
    const arg = args.join(' ');

    // Echo input
    const inputLine: ConsoleLine = { type: 'input', text: `> ${raw}` };

    if (cmd === 'clear') {
      setHistory([{ type: 'system', text: 'KODAXA RELAY CONSOLE · Type `help` for commands · Press ~ or Esc to close' }]);
      return;
    }

    if (cmd === 'exit' || cmd === 'close') {
      addLine([inputLine, { type: 'system', text: 'Relay console closed.' }]);
      setTimeout(() => setOpen(false), 300);
      return;
    }

    const navigate = (path: string, label: string) => {
      addLine([inputLine, { type: 'output', text: `  Routing to ${label}…` }]);
      setTimeout(() => { setOpen(false); router.push(path); }, 400);
    };

    switch (cmd) {
      case 'help':
        addLine([inputLine, { type: 'output', text: HELP_OUTPUT }]); break;
      case 'status':
        addLine([inputLine, { type: 'output', text: STATUS_OUTPUT }]); break;
      case 'ping':
        addLine([inputLine, { type: 'output', text: pingOutput(arg) }]); break;
      case 'whoami':
        addLine([inputLine, { type: 'output', text: '  OPERATIVE: UNIDENTIFIED · Uplink not established · Run `uplink` to authenticate' }]); break;
      case 'uplink':
        navigate('/auth/sign-in', 'Account Services'); break;
      case 'ops':
        navigate('/planner', 'Operations Division'); break;
      case 'intel':
        navigate('/items', 'Intelligence Division'); break;
      case 'commerce':
        navigate('/directory', 'Commerce Division'); break;
      case 'dispatch':
        navigate('/patch-notes', 'Dispatch Newsroom'); break;
      case 'corp':
        navigate('/corporation', 'Corporation Registry'); break;
      default:
        addLine([inputLine, { type: 'error', text: `  System fault: unknown command "${cmd}" — type \`help\` for available commands` }]);
    }
  }, [addLine, router]);

  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') {
      const val = input;
      setCmdHistory((h) => [val, ...h].slice(0, 50));
      setHistoryIdx(-1);
      setInput('');
      runCommand(val);
    }
    if (e.key === 'ArrowUp') {
      e.preventDefault();
      setHistoryIdx((i) => {
        const next = Math.min(i + 1, cmdHistory.length - 1);
        setInput(cmdHistory[next] ?? '');
        return next;
      });
    }
    if (e.key === 'ArrowDown') {
      e.preventDefault();
      setHistoryIdx((i) => {
        const next = Math.max(i - 1, -1);
        setInput(next === -1 ? '' : cmdHistory[next] ?? '');
        return next;
      });
    }
    if (e.key === 'Escape') setOpen(false);
  };

  if (!open) return null;

  return (
    <div
      className="fixed bottom-0 left-0 right-0 z-[150] border-t border-sr-border bg-sr-bg/97 backdrop-blur-sm shadow-2xl"
      style={{ height: 'clamp(260px, 40vh, 480px)' }}
    >
      {/* Header bar */}
      <div className="flex items-center justify-between px-4 py-1.5 border-b border-sr-border bg-sr-surface">
        <div className="flex items-center gap-3">
          <span className="text-xs font-mono text-slate-600 uppercase tracking-[0.35em]">
            Kodaxa Relay Console
          </span>
          <span className="text-xs font-mono text-teal-600">● CONNECTED</span>
        </div>
        <button
          onClick={() => setOpen(false)}
          className="text-xs font-mono text-slate-700 hover:text-slate-400 transition-colors uppercase tracking-wider"
        >
          [Esc] Close
        </button>
      </div>

      {/* Output area */}
      <div
        ref={outputRef}
        className="flex-1 overflow-y-auto px-4 py-3 space-y-0.5 font-mono text-xs"
        style={{ height: 'calc(100% - 64px)' }}
      >
        {history.map((line, i) => (
          <pre
            key={i}
            className={`whitespace-pre-wrap leading-relaxed ${
              line.type === 'input'  ? 'text-cyan-400' :
              line.type === 'error'  ? 'text-red-400'  :
              line.type === 'system' ? 'text-slate-600' :
              'text-slate-400'
            }`}
          >
            {line.text}
          </pre>
        ))}
      </div>

      {/* Input row */}
      <div className="flex items-center border-t border-sr-border px-4 py-2 gap-2 bg-sr-surface">
        <span className="text-cyan-600 font-mono text-xs shrink-0">kdx:~$</span>
        <input
          ref={inputRef}
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={handleKeyDown}
          className="flex-1 bg-transparent font-mono text-xs text-slate-200 placeholder-slate-700 focus:outline-none caret-cyan-400"
          placeholder="type a command…"
          spellCheck={false}
          autoCapitalize="off"
          autoCorrect="off"
        />
      </div>
    </div>
  );
}

// no-op imports removed — visual profile is computed heuristically from tileId

export type GeometryType =
  | 'cube'
  | 'wedge'
  | 'slab_floor'
  | 'slab_wall'
  | 'glass_wall_large'
  | 'glass_corner'
  | 'rod'
  | 'sphere'
  | 'arc'
  | 'prop'
  | 'detailed_door'
  | 'detailed_computer'
  | 'detailed_cabinet'
  // Roofing
  | 'roof_slope'
  | 'roof_ridge'
  | 'roof_hip'
  | 'roof_gable'
  | 'roof_flat'
  // Access
  | 'stairs'
  | 'ramp'
  | 'landing'
  | 'pillar'
  | 'pillar_cap'
  | 'railing';

export type MaterialCategory = 'matte' | 'metal' | 'glass' | 'emissive';

export interface VisualProfile {
  geometry: GeometryType;
  material: MaterialCategory;
}

/** Determines geometry and material bucket for a given tile ID */
export function getTileVisualProfile(tileId: string): VisualProfile {
  // Default fallback
  const defaultProfile: VisualProfile = { geometry: 'cube', material: 'matte' };

  if (!tileId) return defaultProfile;

  // -- 1. Props & Fabricator Details
  if (tileId.includes('door'))             return { geometry: 'detailed_door',     material: 'matte' };
  if (tileId.includes('desktop_computer')) return { geometry: 'detailed_computer', material: 'matte' };
  if (tileId.includes('cabinet'))          return { geometry: 'detailed_cabinet',  material: 'matte' };
  if (tileId.includes('prop'))             return { geometry: 'prop',              material: 'matte' };

  // -- 2. Lights
  if (tileId.includes('light')) {
    let geom: GeometryType = 'cube';
    if (tileId.includes('floor')) geom = 'slab_floor';
    if (tileId.includes('wall'))  geom = 'slab_wall';
    return { geometry: geom, material: 'emissive' };
  }

  // -- 3. Glass (walls/railings)
  if (tileId.includes('railing_glass') || tileId === 'access_railing_glass') {
    return { geometry: 'railing', material: 'glass' };
  }
  if (tileId.includes('glass') || tileId.includes('window')) {
    let geom: GeometryType = 'slab_wall';
    if (tileId.includes('large'))  geom = 'glass_wall_large';
    if (tileId.includes('corner')) geom = 'glass_corner';
    return { geometry: geom, material: 'glass' };
  }

  // -- 4. Roofing
  if (tileId.startsWith('roof_')) {
    const isWood   = tileId.includes('wood');
    const isMetal  = tileId.includes('metal');
    const material: MaterialCategory = isMetal ? 'metal' : 'matte';
    if (tileId.includes('_slope'))   return { geometry: 'roof_slope', material };
    if (tileId.includes('_ridge'))   return { geometry: 'roof_ridge', material };
    if (tileId.includes('_hip'))     return { geometry: 'roof_hip',   material };
    if (tileId.includes('_gable'))   return { geometry: 'roof_gable', material };
    if (tileId.includes('_flat'))    return { geometry: 'roof_flat',  material };
    return { geometry: 'roof_slope', material };
  }

  // -- 5. Access: stairs
  if (tileId.includes('stair')) {
    const isMetal = tileId.includes('metal');
    return { geometry: 'stairs', material: isMetal ? 'metal' : 'matte' };
  }

  // -- 6. Access: ramps
  if (tileId.includes('ramp')) {
    const isMetal = tileId.includes('metal');
    return { geometry: 'ramp', material: isMetal ? 'metal' : 'matte' };
  }

  // -- 7. Access: landings
  if (tileId.includes('landing')) {
    return { geometry: 'landing', material: 'matte' };
  }

  // -- 8. Supports: pillars / columns
  if (tileId.includes('pillar_cap')) {
    return { geometry: 'pillar_cap', material: 'matte' };
  }
  if (tileId.includes('pillar') || tileId.includes('column')) {
    const isMetal = tileId.includes('metal');
    return { geometry: 'pillar', material: isMetal ? 'metal' : 'matte' };
  }

  // -- 9. Access: railings
  if (tileId.includes('railing')) {
    const isMetal = tileId.includes('metal');
    return { geometry: 'railing', material: isMetal ? 'metal' : 'matte' };
  }

  // -- 10. Primitives
  if (tileId === 'fab_arc')    return { geometry: 'arc',    material: 'matte' };
  if (tileId === 'fab_rod')    return { geometry: 'rod',    material: 'metal' };
  if (tileId === 'fab_sphere') return { geometry: 'sphere', material: 'matte' };

  // -- 11. Floors & Pavers
  if (tileId.includes('floor') || tileId.includes('rug') || tileId.startsWith('paver_')) {
    return { geometry: 'slab_floor', material: 'matte' };
  }

  // -- 12. Walls
  if (tileId.includes('wall')) {
    return { geometry: 'slab_wall', material: 'matte' };
  }

  // -- 13. Wedges
  if (tileId.includes('wedge')) {
    const isMetal = tileId.includes('metal');
    return { geometry: 'wedge', material: isMetal ? 'metal' : 'matte' };
  }

  // -- 14. Metal standard blocks
  if (tileId.includes('metal') || tileId.includes('alloy') || tileId.includes('composite')) {
    return { geometry: 'cube', material: 'metal' };
  }

  return defaultProfile;
}

/**
 * use-build-state.ts
 * React hook managing the planner's build state and derived data.
 * One concern: build mutations, validation, and profession selection.
 *
 * This centralizes all build logic so the planner page only handles layout.
 * All game constraint checks are delegated to skill-engine.ts.
 */

'use client';

import { useState, useCallback, useMemo } from 'react';
import type { Build, ToolSlot, StatAllocation } from '@/types/build';
import type { Profession, SkillNode, ProfessionSummary } from '@/types/skill-tree';
import type { SkillFlowNode, SkillFlowEdge } from '@/types/flow-nodes';
import { emptyBuild } from '@/lib/build-encoder';
import { validateBuild } from '@/lib/skill-engine';
import { professionsToFlowGraph } from '@/lib/flow-converter';

export interface BuildStateConfig {
  professions: Profession[];
  professionMap: Map<string, Profession>;
  nodeMap: Map<string, SkillNode>;
  summaries: ProfessionSummary[];
  initialBuild?: Build;
}

export interface BuildState {
  build: Build;
  selectedProfessionIds: string[];
  selectedNodeId: string | null;
  validation: ReturnType<typeof validateBuild>;
  flowNodes: SkillFlowNode[];
  flowEdges: SkillFlowEdge[];
  summaries: ProfessionSummary[];
  nodeMap: Map<string, SkillNode>;
  toggleSkill: (nodeId: string) => void;
  selectNode: (nodeId: string | null) => void;
  toggleProfession: (professionId: string) => void;
  equipTool: (slotIndex: number, profession: Profession) => void;
  clearTool: (slotIndex: number) => void;
  updateStats: (stats: StatAllocation) => void;
  loadBuild: (build: Build) => void;
  resetBuild: () => void;
  setBuildName: (name: string) => void;
}

export function useBuildState(config: BuildStateConfig): BuildState {
  const { professions, professionMap, nodeMap, summaries } = config;

  const [build, setBuild] = useState<Build>(
    config.initialBuild ?? emptyBuild(),
  );

  // Which professions are visible in the canvas
  const [selectedProfessionIds, setSelectedProfessionIds] = useState<string[]>(
    () => {
      // If restoring a shared/saved build, show its professions
      const initial = config.initialBuild;
      if (initial) {
        const fromSkills = initial.activeSkills.map((id) => id.split('.')[0]);
        const fromTools  = initial.toolSlots.filter((s) => s.professionId).map((s) => s.professionId);
        const ids = Array.from(new Set([...fromSkills, ...fromTools])).filter(Boolean);
        if (ids.length > 0) return ids;
      }
      // Default: show the first detailed profession (ranger)
      const detailed = professions.filter((p) => p.nodes.length > 1);
      return detailed.length > 0 ? [detailed[0].id] : [];
    },
  );

  // Currently selected (focused) skill node for the detail panel
  const [selectedNodeId, setSelectedNodeId] = useState<string | null>(null);

  // Validate build whenever it changes
  const validation = useMemo(
    () => validateBuild(build, professionMap, nodeMap),
    [build, professionMap, nodeMap],
  );

  // Compute React Flow graph for selected professions
  const { nodes: flowNodes, edges: flowEdges } = useMemo(() => {
    const selected = selectedProfessionIds
      .map((id) => professionMap.get(id))
      .filter((p): p is Profession => p !== undefined);
    return professionsToFlowGraph(selected, build, nodeMap);
  }, [selectedProfessionIds, build, professionMap, nodeMap]);

  /** Toggle a skill between in_practice and available */
  const toggleSkill = useCallback(
    (nodeId: string) => {
      // Also select the node for the detail panel
      setSelectedNodeId(nodeId);
      setBuild((prev) => {
        const node = nodeMap.get(nodeId);
        if (!node) return prev;

        const isActive = prev.activeSkills.includes(nodeId);
        const isAtrophied = prev.atrophiedSkills.includes(nodeId);

        if (isActive) {
          return {
            ...prev,
            activeSkills: prev.activeSkills.filter((id) => id !== nodeId),
            atrophiedSkills: [...prev.atrophiedSkills, nodeId],
            updatedAt: new Date().toISOString(),
          };
        }

        if (isAtrophied) {
          return {
            ...prev,
            activeSkills: [...prev.activeSkills, nodeId],
            atrophiedSkills: prev.atrophiedSkills.filter((id) => id !== nodeId),
            updatedAt: new Date().toISOString(),
          };
        }

        // Block activation if prerequisites are not met (locked node)
        const knownSkills = new Set([...prev.activeSkills, ...prev.atrophiedSkills]);
        const prereqsMet = node.prerequisites.every((id) => knownSkills.has(id));
        if (!prereqsMet) return prev;

        return {
          ...prev,
          activeSkills: [...prev.activeSkills, nodeId],
          updatedAt: new Date().toISOString(),
        };
      });
    },
    [nodeMap],
  );

  /** Select a node for the detail panel without toggling skill state */
  const selectNode = useCallback((nodeId: string | null) => {
    setSelectedNodeId(nodeId);
  }, []);

  /** Toggle profession visibility in the canvas */
  const toggleProfession = useCallback((professionId: string) => {
    setSelectedProfessionIds((prev) =>
      prev.includes(professionId)
        ? prev.filter((id) => id !== professionId)
        : [...prev, professionId],
    );
  }, []);

  /** Equip a profession's tool into a slot */
  const equipTool = useCallback((slotIndex: number, profession: Profession) => {
    setBuild((prev) => {
      const newSlots = [...prev.toolSlots];
      newSlots[slotIndex] = {
        toolName: profession.tool.name,
        professionId: profession.id,
        activeSpecials: [undefined, undefined],
      };
      return { ...prev, toolSlots: newSlots, updatedAt: new Date().toISOString() };
    });
  }, []);

  /** Clear a tool slot */
  const clearTool = useCallback((slotIndex: number) => {
    setBuild((prev) => {
      const newSlots = [...prev.toolSlots];
      newSlots[slotIndex] = { toolName: '', professionId: '', activeSpecials: [undefined, undefined] };
      return { ...prev, toolSlots: newSlots, updatedAt: new Date().toISOString() };
    });
  }, []);

  /** Update stat pool allocation */
  const updateStats = useCallback((stats: StatAllocation) => {
    setBuild((prev) => ({ ...prev, stats, updatedAt: new Date().toISOString() }));
  }, []);

  /** Load a saved build (replaces current build entirely) */
  const loadBuild = useCallback((newBuild: Build) => {
    setBuild(newBuild);
    setSelectedNodeId(null);
    // Show professions from both active skills and equipped tool slots
    const fromSkills = newBuild.activeSkills.map((id) => id.split('.')[0]);
    const fromTools  = newBuild.toolSlots.filter((s) => s.professionId).map((s) => s.professionId);
    const profIds = Array.from(new Set([...fromSkills, ...fromTools])).filter(Boolean);
    if (profIds.length > 0) setSelectedProfessionIds(profIds);
  }, []);

  /** Reset build to empty state */
  const resetBuild = useCallback(() => {
    setBuild(emptyBuild());
    setSelectedNodeId(null);
  }, []);

  /** Update build name */
  const setBuildName = useCallback((name: string) => {
    setBuild((prev) => ({ ...prev, name, updatedAt: new Date().toISOString() }));
  }, []);

  return {
    build,
    selectedProfessionIds,
    selectedNodeId,
    validation,
    flowNodes,
    flowEdges,
    summaries,
    nodeMap,
    toggleSkill,
    selectNode,
    toggleProfession,
    equipTool,
    clearTool,
    updateStats,
    loadBuild,
    resetBuild,
    setBuildName,
  };
}

/**
 * use-dashboard.ts
 * Hooks for the Personal Analytics Dashboard.
 * One concern: localStorage CRUD for session logs, Klaatu ledger, and skill progress.
 *
 * Follows the same SSR-safe pattern as use-saved-builds.ts:
 *   - State initialized empty → hydrated from localStorage in useEffect
 *   - All writes immediately sync to localStorage via helper functions
 */

'use client';

import { useState, useCallback, useEffect } from 'react';
import type {
  SessionLog,
  KlaatuEntry,
  KlaatuCategory,
  SkillProgress,
  ActivityEntry,
} from '@/types/dashboard';

// ── Storage keys ────────────────────────────────────────────────────

const SESSION_KEY      = 'sr_session_logs';
const KLAATU_KEY       = 'sr_klaatu_ledger';
const SKILL_PROG_KEY   = 'sr_skill_progress';
const MAX_SESSIONS     = 200;
const MAX_KLAATU       = 500;

// ── Helpers ─────────────────────────────────────────────────────────

function load<T>(key: string): T[] {
  if (typeof window === 'undefined') return [];
  try {
    const raw = localStorage.getItem(key);
    if (!raw) return [];
    return JSON.parse(raw) as T[];
  } catch {
    return [];
  }
}

function save<T>(key: string, data: T[]): void {
  if (typeof window === 'undefined') return;
  try {
    localStorage.setItem(key, JSON.stringify(data));
  } catch {
    // Storage full — silently ignore
  }
}

function uid(): string {
  return `${Date.now()}-${Math.random().toString(36).slice(2, 7)}`;
}

// ── Session Logs Hook ───────────────────────────────────────────────

export interface SessionLogsHook {
  sessions: SessionLog[];
  hydrated: boolean;
  addSession: (input: Omit<SessionLog, 'id'>) => void;
  updateSession: (id: string, updates: Partial<SessionLog>) => void;
  deleteSession: (id: string) => void;
  totalDuration: number;
  totalKlaatuEarned: number;
  totalKlaatuSpent: number;
}

export function useSessionLogs(): SessionLogsHook {
  const [sessions, setSessions] = useState<SessionLog[]>([]);
  const [hydrated, setHydrated] = useState(false);

  useEffect(() => {
    setSessions(load<SessionLog>(SESSION_KEY));
    setHydrated(true);
  }, []);

  const addSession = useCallback((input: Omit<SessionLog, 'id'>) => {
    setSessions((prev) => {
      const entry: SessionLog = { id: uid(), ...input };
      const updated = [entry, ...prev].slice(0, MAX_SESSIONS);
      save(SESSION_KEY, updated);
      return updated;
    });
  }, []);

  const updateSession = useCallback((id: string, updates: Partial<SessionLog>) => {
    setSessions((prev) => {
      const updated = prev.map((s) => (s.id === id ? { ...s, ...updates } : s));
      save(SESSION_KEY, updated);
      return updated;
    });
  }, []);

  const deleteSession = useCallback((id: string) => {
    setSessions((prev) => {
      const updated = prev.filter((s) => s.id !== id);
      save(SESSION_KEY, updated);
      return updated;
    });
  }, []);

  const totalDuration = sessions.reduce((acc, s) => acc + s.duration_minutes, 0);
  const totalKlaatuEarned = sessions.reduce((acc, s) => acc + s.klaatu_earned, 0);
  const totalKlaatuSpent = sessions.reduce((acc, s) => acc + s.klaatu_spent, 0);

  return {
    sessions, hydrated, addSession, updateSession, deleteSession,
    totalDuration, totalKlaatuEarned, totalKlaatuSpent,
  };
}

// ── Klaatu Ledger Hook ──────────────────────────────────────────────

export interface KlaatuLedgerHook {
  entries: KlaatuEntry[];
  hydrated: boolean;
  addEntry: (category: KlaatuCategory, amount: number, description: string, sessionId?: string) => void;
  deleteEntry: (id: string) => void;
  balance: number;
  income: number;
  expenses: number;
}

export function useKlaatuLedger(): KlaatuLedgerHook {
  const [entries, setEntries] = useState<KlaatuEntry[]>([]);
  const [hydrated, setHydrated] = useState(false);

  useEffect(() => {
    setEntries(load<KlaatuEntry>(KLAATU_KEY));
    setHydrated(true);
  }, []);

  const addEntry = useCallback(
    (category: KlaatuCategory, amount: number, description: string, sessionId?: string) => {
      setEntries((prev) => {
        const entry: KlaatuEntry = {
          id: uid(),
          date: new Date().toISOString(),
          amount,
          category,
          description,
          session_id: sessionId,
        };
        const updated = [entry, ...prev].slice(0, MAX_KLAATU);
        save(KLAATU_KEY, updated);
        return updated;
      });
    },
    [],
  );

  const deleteEntry = useCallback((id: string) => {
    setEntries((prev) => {
      const updated = prev.filter((e) => e.id !== id);
      save(KLAATU_KEY, updated);
      return updated;
    });
  }, []);

  const balance = entries.reduce((acc, e) => acc + e.amount, 0);
  const income = entries.filter((e) => e.amount > 0).reduce((acc, e) => acc + e.amount, 0);
  const expenses = entries.filter((e) => e.amount < 0).reduce((acc, e) => acc + Math.abs(e.amount), 0);

  return { entries, hydrated, addEntry, deleteEntry, balance, income, expenses };
}

// ── Skill Progress Hook ─────────────────────────────────────────────

export interface SkillProgressHook {
  progress: SkillProgress[];
  hydrated: boolean;
  logXp: (professionId: string, professionName: string, xp: number) => void;
  resetProfession: (professionId: string) => void;
}

export function useSkillProgress(): SkillProgressHook {
  const [progress, setProgress] = useState<SkillProgress[]>([]);
  const [hydrated, setHydrated] = useState(false);

  useEffect(() => {
    setProgress(load<SkillProgress>(SKILL_PROG_KEY));
    setHydrated(true);
  }, []);

  const logXp = useCallback((professionId: string, professionName: string, xp: number) => {
    setProgress((prev) => {
      const existing = prev.find((p) => p.profession_id === professionId);
      const entry: SkillProgress = existing
        ? {
            ...existing,
            current_xp: existing.current_xp + xp,
            sessions_logged: existing.sessions_logged + 1,
            last_active: new Date().toISOString(),
          }
        : {
            profession_id: professionId,
            profession_name: professionName,
            current_xp: xp,
            sessions_logged: 1,
            last_active: new Date().toISOString(),
          };
      const updated = [entry, ...prev.filter((p) => p.profession_id !== professionId)];
      save(SKILL_PROG_KEY, updated);
      return updated;
    });
  }, []);

  const resetProfession = useCallback((professionId: string) => {
    setProgress((prev) => {
      const updated = prev.filter((p) => p.profession_id !== professionId);
      save(SKILL_PROG_KEY, updated);
      return updated;
    });
  }, []);

  return { progress, hydrated, logXp, resetProfession };
}

