}

// ── Vendor Listings Hook ────────────────────────────────────────────

export interface VendorListingsHook {
  listings: VendorListing[];
  hydrated: boolean;
  addListing: (itemName: string, quantity: number, listPrice: number) => void;
  updateListing: (id: string, updates: Partial<VendorListing>) => void;
  markSold: (id: string, buyerName?: string) => void;
  withdrawListing: (id: string) => void;
  deleteListing: (id: string) => void;
  activeCount: number;
  activeListings: VendorListing[];
  slotsRemaining: number;
  totalListingFees: number;
}

export function useVendorListings(): VendorListingsHook {
  const [listings, setListings] = useState<VendorListing[]>([]);
  const [hydrated, setHydrated] = useState(false);

  useEffect(() => {
    setListings(load<VendorListing>(LISTINGS_KEY));
    setHydrated(true);
  }, []);

  const addListing = useCallback((itemName: string, quantity: number, listPrice: number) => {
    setListings((prev) => {
      const totalValue = quantity * listPrice;
      const fee = calculateListingFee(quantity, listPrice);
      const entry: VendorListing = {
        id: uid(),
        item_name: itemName,
        quantity,
        list_price: listPrice,
        listing_fee: fee,
        total_value: totalValue,
        status: 'active',
        listed_at: new Date().toISOString(),
      };
      const updated = [entry, ...prev].slice(0, MAX_LISTINGS);
      save(LISTINGS_KEY, updated);
      return updated;
    });
  }, []);

  const updateListing = useCallback((id: string, updates: Partial<VendorListing>) => {
    setListings((prev) => {
      const updated = prev.map((l) => (l.id === id ? { ...l, ...updates } : l));
      save(LISTINGS_KEY, updated);
      return updated;
    });
  }, []);

  const markSold = useCallback((id: string, buyerName?: string) => {
    setListings((prev) => {
      const updated = prev.map((l) =>
        l.id === id
          ? { ...l, status: 'sold' as ListingStatus, sold_at: new Date().toISOString(), buyer_name: buyerName }
          : l,
      );
      save(LISTINGS_KEY, updated);
      return updated;
    });
  }, []);

  const withdrawListing = useCallback((id: string) => {
    setListings((prev) => {
      const updated = prev.map((l) =>
        l.id === id ? { ...l, status: 'withdrawn' as ListingStatus } : l,
      );
      save(LISTINGS_KEY, updated);
      return updated;
    });
  }, []);

  const deleteListing = useCallback((id: string) => {
    setListings((prev) => {
      const updated = prev.filter((l) => l.id !== id);
      save(LISTINGS_KEY, updated);
      return updated;
    });
  }, []);

  const activeListings = useMemo(() => listings.filter((l) => l.status === 'active'), [listings]);
  const activeCount = activeListings.length;
  const slotsRemaining = KIOSK_MAX_LISTINGS - activeCount;
  const totalListingFees = useMemo(
    () => listings.reduce((acc, l) => acc + l.listing_fee, 0),
    [listings],
  );

  return {
    listings, hydrated, addListing, updateListing, markSold,
    withdrawListing, deleteListing, activeCount, activeListings,
    slotsRemaining, totalListingFees,
  };
}

// ── Trade Log Hook ──────────────────────────────────────────────────

export interface TradeLogHook {
  trades: TradeTransaction[];
  hydrated: boolean;
  addTrade: (input: Omit<TradeTransaction, 'id'>) => void;
  deleteTrade: (id: string) => void;
  netProfit: number;
  totalSales: number;
  totalPurchases: number;
}

export function useTradeLog(): TradeLogHook {
  const [trades, setTrades] = useState<TradeTransaction[]>([]);
  const [hydrated, setHydrated] = useState(false);

  useEffect(() => {
    setTrades(load<TradeTransaction>(TRADES_KEY));
    setHydrated(true);
  }, []);

  const addTrade = useCallback((input: Omit<TradeTransaction, 'id'>) => {
    setTrades((prev) => {
      const entry: TradeTransaction = { id: uid(), ...input };
      const updated = [entry, ...prev].slice(0, MAX_TRADES);
      save(TRADES_KEY, updated);
      return updated;
    });
  }, []);

  const deleteTrade = useCallback((id: string) => {
    setTrades((prev) => {
      const updated = prev.filter((t) => t.id !== id);
      save(TRADES_KEY, updated);
      return updated;
    });
  }, []);

  const netProfit = useMemo(() => netProfitLoss(trades), [trades]);
  const totalSales = useMemo(
    () => trades.filter((t) => t.type === 'sale').reduce((acc, t) => acc + t.total, 0),
    [trades],
  );
  const totalPurchases = useMemo(
    () => trades.filter((t) => t.type === 'purchase').reduce((acc, t) => acc + t.total, 0),
    [trades],
  );

  return { trades, hydrated, addTrade, deleteTrade, netProfit, totalSales, totalPurchases };
}

// ── Price History Hook ──────────────────────────────────────────────

export interface PriceHistoryHook {
  prices: PriceHistoryEntry[];
  hydrated: boolean;
  addPrice: (itemName: string, unitPrice: number, planet: string, source: PriceSource) => void;
  deletePrice: (id: string) => void;
  getPricesForItem: (itemName: string) => PriceHistoryEntry[];
}

export function usePriceHistory(): PriceHistoryHook {
  const [prices, setPrices] = useState<PriceHistoryEntry[]>([]);
  const [hydrated, setHydrated] = useState(false);

  useEffect(() => {
    setPrices(load<PriceHistoryEntry>(PRICES_KEY));
    setHydrated(true);
  }, []);

  const addPrice = useCallback(
    (itemName: string, unitPrice: number, planet: string, source: PriceSource) => {
      setPrices((prev) => {
        const entry: PriceHistoryEntry = {
          id: uid(),
          item_name: itemName,
          unit_price: unitPrice,
          planet,
          date: new Date().toISOString(),
          source,
        };
        const updated = [entry, ...prev].slice(0, MAX_PRICES);
        save(PRICES_KEY, updated);
        return updated;
      });
    },
    [],
  );

  const deletePrice = useCallback((id: string) => {
    setPrices((prev) => {
      const updated = prev.filter((p) => p.id !== id);
      save(PRICES_KEY, updated);
      return updated;
    });
  }, []);

  const getPricesForItem = useCallback(
    (itemName: string) => prices.filter((p) => p.item_name === itemName),
    [prices],
  );

  return { prices, hydrated, addPrice, deletePrice, getPricesForItem };
}

/**
 * building-encoder.ts
 * Encode/decode BuildingState to/from URL-safe strings.
 * One concern: enabling shareable URLs without a backend.
 */

import type { BuildingState, PlacedCell, ClaimLayer } from '@/types/building';

const DEFAULT_LAYERS: ClaimLayer[] = [
  { index: -2, label: 'Basement 2', color: 'bg-stone-900' },
  { index: -1, label: 'Basement 1', color: 'bg-stone-800' },
  { index: 0,  label: 'Ground Floor', color: 'bg-stone-700' },
  { index: 1,  label: 'Floor 1', color: 'bg-stone-600' },
  { index: 2,  label: 'Floor 2', color: 'bg-stone-600' },
  { index: 3,  label: 'Roof', color: 'bg-stone-500' },
];

export function emptyBuildingState(): BuildingState {
  return {
    name: 'My Homestead',
    claimX: 10,
    claimZ: 10,
    hiddenLayers: [],
    layers: DEFAULT_LAYERS,
    activeLayer: 0,
    cells: [],
    selectedTileId: null,
    mode: 'place',
    currentRotation: 0,
    updatedAt: new Date().toISOString(),
  };
}

/**
 * Cell format: x.y.z.rot,tileId — rows separated by "~"
 * URL params:
 *   n  = name
 *   cx = claimX (omit if 10)
 *   cz = claimZ (omit if 10)
 *   al = activeLayer (omit if 0)
 *   hl = hiddenLayers comma-separated (omit if empty)
 *   l  = customized layer labels: idx.label~idx.label
 *   c  = cells
 */
export function encodeBuildingState(state: BuildingState): string {
  const params = new URLSearchParams();

  if (state.name !== 'My Homestead') {
    params.set('n', state.name);
  }

  if ((state.claimX ?? 10) !== 10) {
    params.set('cx', String(state.claimX));
  }
  if ((state.claimZ ?? 10) !== 10) {
    params.set('cz', String(state.claimZ));
  }

  if (state.activeLayer !== 0) {
    params.set('al', state.activeLayer.toString());
  }

  const hiddenLayers = state.hiddenLayers ?? [];
  if (hiddenLayers.length > 0) {
    params.set('hl', hiddenLayers.join(','));
  }

  if (state.cells.length > 0) {
    const compactCells = state.cells
      .map((c) => `${c.x}.${c.y}.${c.z}.${c.rotation || 0},${c.tileId}`)
      .join('~');
    params.set('c', compactCells);
  }

  // Only encode layer names if they've been customized
  const customLayers = state.layers.filter(
    (l, i) => l.label !== DEFAULT_LAYERS[i]?.label
  );
  if (customLayers.length > 0) {
    const encodedLayers = customLayers
      .map((l) => `${l.index}.${encodeURIComponent(l.label)}`)
      .join('~');
    params.set('l', encodedLayers);
  }

  return params.toString();
}

/** Decode URL params back into full state */
export function decodeBuildingState(searchParams: URLSearchParams): BuildingState {
  const state = emptyBuildingState();

  if (!searchParams) return state;

  const n = searchParams.get('n');
  if (n) state.name = n;

  const cx = searchParams.get('cx');
  if (cx) state.claimX = Math.max(4, Math.min(32, parseInt(cx, 10) || 10));

  const cz = searchParams.get('cz');
  if (cz) state.claimZ = Math.max(4, Math.min(32, parseInt(cz, 10) || 10));

  const al = searchParams.get('al');
  if (al) state.activeLayer = parseInt(al, 10) || 0;

  const hl = searchParams.get('hl');
  if (hl) {
    state.hiddenLayers = hl
      .split(',')
      .map((s) => parseInt(s, 10))
      .filter((n) => !isNaN(n));
  }

  const c = searchParams.get('c');
  if (c) {
    state.cells = c.split('~').map((chunk, i) => {
      const parts = chunk.split('.');
      const tail = parts.slice(3).join('.');

      let rotation = 0;
      let tileId = tail;

      const commaIdx = tail.indexOf(',');
      if (commaIdx !== -1) {
        const rotStr = tail.substring(0, commaIdx);
        const parsed = parseInt(rotStr, 10);
        if (!isNaN(parsed)) {
          rotation = parsed;
          tileId = tail.substring(commaIdx + 1);
        }
      }

      return {
        id: `cell_${Date.now()}_${i}`,
        x: parseInt(parts[0], 10),
        y: parseInt(parts[1], 10),
        z: parseInt(parts[2], 10),
        rotation,
        tileId,
      };
    });
  }

  const l = searchParams.get('l');
  if (l) {
    l.split('~').forEach((chunk) => {
      const parts = chunk.split('.');
      const index = parseInt(parts[0], 10);
      const label = decodeURIComponent(parts[1]);
      const layer = state.layers.find((ly) => ly.index === index);
      if (layer) layer.label = label;
    });
  }

  return state;
}

export function generateBuildingShareUrl(state: BuildingState, origin: string): string {
  const encoded = encodeBuildingState(state);
  return `${origin}/building${encoded ? `?${encoded}` : ''}`;
}

/**
 * chain-resolver.ts
 * Resolves crafting dependency chains for Stars Reach recipes.
 * One concern: walking recipe dependencies to build a full production tree.
 *
 * Given a target recipe, this module produces:
 *   - A flat list of all required intermediate crafting steps
 *   - A tree structure for visualization
 *   - A total raw materials shopping list
 *
 * This is pure logic — no React, no side effects.
 */

import type { Recipe, RecipeIngredient } from '@/types/crafting';

/** A node in the crafting dependency tree */
export interface ChainNode {
  recipeId: string;
  recipeName: string;
  stationId: string;
  /** Quantity of this recipe's output needed */
  quantityNeeded: number;
  /** Number of times this recipe must be crafted */
  craftCount: number;
  /** Child nodes (sub-components that feed into this recipe) */
  children: ChainNode[];
  /** Depth in the tree (0 = target item) */
  depth: number;
}

/** A flat entry in the shopping list */
export interface ShoppingListEntry {
  resourceId: string;
  resourceName: string;
  /** Total quantity needed across all crafting steps */
  totalQuantity: number;
  /** Is this a raw material (no recipe to make it) or an intermediate? */
  isRaw: boolean;
}

/** Complete resolved chain result */
export interface ResolvedChain {
  /** Tree structure for visualization */
  tree: ChainNode;
  /** Flat ordered list of crafting steps (bottom-up) */
  steps: CraftingStep[];
  /** Total raw materials needed */
  shoppingList: ShoppingListEntry[];
}

/** A single crafting step in the production sequence */
export interface CraftingStep {
  recipeId: string;
  recipeName: string;
  stationId: string;
  craftCount: number;
  ingredients: { resourceId: string; totalQuantity: number }[];
  /** Order index (0 = craft first) */
  order: number;
}

/**
 * Resolve the full dependency chain for a target recipe.
 *
 * @param targetRecipeId - The recipe to craft
 * @param quantity - How many of the target item to produce
 * @param recipeMap - All recipes indexed by ID
 * @param recipeByOutput - Recipes indexed by output item ID
 */
export function resolveChain(
  targetRecipeId: string,
  quantity: number,
  recipeMap: Map<string, Recipe>,
  recipeByOutput: Map<string, Recipe>,
): ResolvedChain {
  const rawMaterials = new Map<string, ShoppingListEntry>();
  const stepMap = new Map<string, CraftingStep>();
  let stepOrder = 0;

  const tree = buildNode(
    targetRecipeId,
    quantity,
    0,
    recipeMap,
    recipeByOutput,
    rawMaterials,
    stepMap,
    { order: stepOrder },
  );

  // Convert step map to ordered array (reverse so leaves come first)
  const steps = Array.from(stepMap.values()).sort(
    (a, b) => b.order - a.order,
  );
  // Re-index order so 0 = craft first
  steps.forEach((s, i) => (s.order = i));

  return {
    tree,
    steps,
    shoppingList: Array.from(rawMaterials.values()),
  };
}

/** Recursively build a dependency tree node */
function buildNode(
  recipeId: string,
  quantityNeeded: number,
  depth: number,
  recipeMap: Map<string, Recipe>,
  recipeByOutput: Map<string, Recipe>,
  rawMaterials: Map<string, ShoppingListEntry>,
  stepMap: Map<string, CraftingStep>,
  orderRef: { order: number },
): ChainNode {
  const recipe = recipeMap.get(recipeId);
  if (!recipe) {
    return {
      recipeId,
      recipeName: recipeId,
      stationId: 'unknown',
      quantityNeeded,
      craftCount: quantityNeeded,
      children: [],
      depth,
    };
  }

  // How many crafts needed (ceil in case output quantity > 1)
  const craftCount = Math.ceil(quantityNeeded / recipe.output.quantity);

  const children: ChainNode[] = [];

  for (const ing of recipe.ingredients) {
    const totalIngNeeded = ing.quantity * craftCount;
    const subRecipe = recipeByOutput.get(ing.resourceId);

    if (subRecipe) {
      // This ingredient is itself crafted — recurse
      const child = buildNode(
        subRecipe.id,
        totalIngNeeded,
        depth + 1,
        recipeMap,
        recipeByOutput,
        rawMaterials,
        stepMap,
        orderRef,
      );
      children.push(child);
    } else {
      // Raw material — add to shopping list
      accumulateRaw(rawMaterials, ing.resourceId, totalIngNeeded);
    }
  }

  // Register this as a crafting step
  if (!stepMap.has(recipeId)) {
    stepMap.set(recipeId, {
      recipeId,
      recipeName: recipe.name,
      stationId: recipe.stationId,
      craftCount,
      ingredients: recipe.ingredients.map((ing) => ({
        resourceId: ing.resourceId,
        totalQuantity: ing.quantity * craftCount,
      })),
      order: orderRef.order++,
    });
  } else {
    // Recipe already in steps — increase craft count
    const existing = stepMap.get(recipeId)!;
    existing.craftCount += craftCount;
    existing.ingredients.forEach((ingStep, i) => {
      ingStep.totalQuantity += recipe.ingredients[i].quantity * craftCount;
    });
  }

  return {
    recipeId,
    recipeName: recipe.name,
    stationId: recipe.stationId,
    quantityNeeded,
    craftCount,
    children,
    depth,
  };
}

/** Accumulate raw material quantities in the shopping list */
function accumulateRaw(
  map: Map<string, ShoppingListEntry>,
  resourceId: string,
  quantity: number,
): void {
  const existing = map.get(resourceId);
  if (existing) {
    existing.totalQuantity += quantity;
  } else {
    map.set(resourceId, {
      resourceId,
      resourceName: resourceId, // Caller can enrich with display names
      totalQuantity: quantity,
      isRaw: true,
    });
  }
}

/**
 * Build the recipeByOutput lookup map.
 * Maps output item IDs to the recipe that produces them.
 */
export function buildOutputIndex(
  recipeMap: Map<string, Recipe>,
): Map<string, Recipe> {
  const index = new Map<string, Recipe>();
  for (const recipe of recipeMap.values()) {
    index.set(recipe.output.itemId, recipe);
  }
  return index;
}

/**
 * lib/dispatch/actions.ts
 * Server Actions for dispatch post mutations.
 * One concern: create, update, publish, unpublish, delete posts.
 *
 * All writes require ceo or officer role (checked via get_user_role()).
 */

'use server';

import { revalidatePath } from 'next/cache';
import { createClient } from '@/lib/supabase/server';
import type { DispatchPost, Block, DispatchCategory } from '@/types/dispatch';

interface ActionResult<T = void> {
  success: boolean;
  data?: T;
  error?: string;
}

export interface SavePostInput {
  slug: string;
  title: string;
  category: DispatchCategory;
  author: string;
  eyebrow?: string;
  ref_id?: string;
  tag?: string;
  summary: string;
  tags: string[];
  content: Block[];
}

async function assertEditor(supabase: Awaited<ReturnType<typeof createClient>>) {
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) return 'Not authenticated.';

  const { data } = await supabase
    .from('crafter_profiles')
    .select('role')
    .eq('id', user.id)
    .single();

  if (!data || !['ceo', 'officer'].includes(data.role)) {
    return 'Insufficient clearance — CEO or Officer required.';
  }
  return null;
}

/** Upsert a post as draft */
export async function savePost(input: SavePostInput): Promise<ActionResult<{ slug: string }>> {
  const supabase = await createClient();
  const authError = await assertEditor(supabase);
  if (authError) return { success: false, error: authError };

  const { data, error } = await supabase
    .from('dispatch_posts')
    .upsert(
      { ...input, status: 'draft' },
      { onConflict: 'slug' },
    )
    .select('slug')
    .single();

  if (error) {
    return { success: false, error: error.message };
  }

  revalidatePath('/corp/hq/dispatch');
  return { success: true, data: { slug: data.slug } };
}

/** Publish a post — sets status=published and published_at=today if not set */
export async function publishPost(slug: string): Promise<ActionResult> {
  const supabase = await createClient();
  const authError = await assertEditor(supabase);
  if (authError) return { success: false, error: authError };

  const today = new Date().toISOString().split('T')[0];

  const { error } = await supabase
    .from('dispatch_posts')
    .update({ status: 'published', published_at: today })
    .eq('slug', slug)
    .is('published_at', null); // only set date if not already set

  // If above matched nothing (date was already set), just flip status
  if (error) {
    const { error: e2 } = await supabase
      .from('dispatch_posts')
      .update({ status: 'published' })
      .eq('slug', slug);
    if (e2) return { success: false, error: e2.message };
  }

  revalidatePath('/dispatch');
  revalidatePath(`/dispatch/${slug}`);
  revalidatePath('/corp/hq/dispatch');
  revalidatePath('/');
  return { success: true };
}

/** Retract a post back to draft */
export async function unpublishPost(slug: string): Promise<ActionResult> {
  const supabase = await createClient();
  const authError = await assertEditor(supabase);
  if (authError) return { success: false, error: authError };

  const { error } = await supabase
    .from('dispatch_posts')
    .update({ status: 'draft' })
    .eq('slug', slug);

  if (error) return { success: false, error: error.message };

  revalidatePath('/dispatch');
  revalidatePath(`/dispatch/${slug}`);
  revalidatePath('/corp/hq/dispatch');
  revalidatePath('/');
  return { success: true };
}

/** Hard delete — CEO only enforced by RLS */
export async function deletePost(slug: string): Promise<ActionResult> {
  const supabase = await createClient();
  const authError = await assertEditor(supabase);
  if (authError) return { success: false, error: authError };

  const { error } = await supabase
    .from('dispatch_posts')
    .delete()
    .eq('slug', slug);

  if (error) return { success: false, error: error.message };

  revalidatePath('/dispatch');
  revalidatePath('/corp/hq/dispatch');
  revalidatePath('/');
  return { success: true };
}

/**
 * flow-converter.ts
 * Converts Profession data into @xyflow/react Node[] and Edge[] arrays.
 * One concern: data transformation from game types to React Flow types.
 *
 * This is a pure function module — no React, no side effects.
 */

import type { Profession, SkillNode, SkillEdge } from '@/types/skill-tree';
import type { SkillFlowNode, SkillFlowEdge, SkillNodeData } from '@/types/flow-nodes';
import type { Build } from '@/types/build';

/** Determine the visual state of a node based on the current build */
function resolveNodeState(
  node: SkillNode,
  build: Build,
  allNodes: Map<string, SkillNode>,
): SkillNodeData['state'] {
  // WIP nodes are always shown as WIP regardless of build
  if (!node.implemented) return 'wip';

  // Check if this node is actively selected
  if (build.activeSkills.includes(node.id)) return 'in_practice';

  // Check if atrophied
  if (build.atrophiedSkills.includes(node.id)) return 'out_of_practice';

  // Check prerequisites — all must be in_practice or out_of_practice
  const prereqsMet = node.prerequisites.every((prereqId) => {
    return (
      build.activeSkills.includes(prereqId) ||
      build.atrophiedSkills.includes(prereqId)
    );
  });

  // Root nodes (no prerequisites) are always available
  if (node.prerequisites.length === 0) return 'available';

  return prereqsMet ? 'available' : 'locked';
}

/**
 * Convert a single profession's nodes into React Flow nodes.
 * Applies an optional offset so multiple trees can be placed side-by-side.
 */
export function professionToFlowNodes(
  profession: Profession,
  build: Build,
  allNodes: Map<string, SkillNode>,
  offset: { x: number; y: number } = { x: 0, y: 0 },
): SkillFlowNode[] {
  return profession.nodes.map((node) => ({
    id: node.id,
    type: 'skill' as const,
    position: {
      x: node.position.x + offset.x,
      y: node.position.y + offset.y,
    },
    data: {
      label: node.name,
      description: node.description,
      professionId: node.professionId,
      state: resolveNodeState(node, build, allNodes),
      tier: node.tier,
      special: node.special,
      unlocksTree: node.unlocksTree,
      implemented: node.implemented,
      costs: node.costs,
    },
  }));
}

/** Convert a profession's edges into React Flow edges with styling */
export function professionToFlowEdges(
  profession: Profession,
): SkillFlowEdge[] {
  return profession.edges.map((edge) => ({
    id: `${edge.source}->${edge.target}`,
    source: edge.source,
    target: edge.target,
    type: 'smoothstep',
    animated: edge.crossTree,
    style: {
      stroke: edge.crossTree ? '#22d3ee' : '#64748b',
      strokeWidth: edge.crossTree ? 2 : 1.5,
    },
    data: {
      crossTree: edge.crossTree,
    },
  }));
}

/**
 * Convert multiple professions into a combined flow graph.
 * Each profession is offset horizontally so trees don't overlap.
 */
export function professionsToFlowGraph(
  professions: Profession[],
  build: Build,
  allNodes: Map<string, SkillNode>,
): { nodes: SkillFlowNode[]; edges: SkillFlowEdge[] } {
  const nodes: SkillFlowNode[] = [];
  const edges: SkillFlowEdge[] = [];

  // Horizontal spacing between profession trees
  const TREE_SPACING = 900;

  professions.forEach((prof, index) => {
    const offset = { x: index * TREE_SPACING, y: 0 };
    nodes.push(...professionToFlowNodes(prof, build, allNodes, offset));
    edges.push(...professionToFlowEdges(prof));
  });

  // Add cross-tree edges between professions
  // (e.g., ranger.unlock_camping -> camping.base)
  for (const prof of professions) {
    for (const node of prof.nodes) {
      if (node.unlocksTree) {
        const targetBaseId = `${node.unlocksTree}.base`;
        // Only add if target exists in our node set
        if (nodes.some((n) => n.id === targetBaseId)) {
          edges.push({
            id: `cross:${node.id}->${targetBaseId}`,
            source: node.id,
            target: targetBaseId,
            type: 'smoothstep',
            animated: true,
            style: {
              stroke: '#22d3ee',
              strokeWidth: 2,
              strokeDasharray: '5 5',
            },
            data: { crossTree: true },
          });
        }
      }
    }
  }

  return { nodes, edges };
}
